<?php
if ( ! defined( 'ABSPATH' ) ) { exit; }
final class EBM_Stripe {
	public static function routes(){register_rest_route('ebm/v1','/stripe-webhook',array('methods'=>'POST','callback'=>array(__CLASS__,'webhook'),'permission_callback'=>'__return_true'));}
	private static function request($endpoint,$body){$key=EBM_Settings::secret('stripe_secret_key'); if(!$key){return new WP_Error('ebm_no_stripe',__('Stripe secret key is missing.','electrical-booking-manager'));} $res=wp_remote_post('https://api.stripe.com/v1/'.ltrim($endpoint,'/'),array('timeout'=>20,'headers'=>array('Authorization'=>'Bearer '.$key),'body'=>$body)); $data=json_decode(wp_remote_retrieve_body($res),true); if(is_wp_error($res)){return $res;} if(wp_remote_retrieve_response_code($res)>=400){return new WP_Error('ebm_stripe_error',$data['error']['message']??__('Stripe request failed.','electrical-booking-manager'));} return $data;}
	public static function checkout($booking_id,$amount,$type='deposit'){global $wpdb;$b=$wpdb->get_row($wpdb->prepare('SELECT b.*,c.email FROM '.EBM_Helpers::table('bookings').' b INNER JOIN '.EBM_Helpers::table('customers').' c ON c.id=b.customer_id WHERE b.id=%d',$booking_id)); if(!$b){return new WP_Error('ebm_missing_booking',__('Booking not found.','electrical-booking-manager'));} $success=add_query_arg(array('ebm_booking'=>$b->public_token,'payment'=>'success'),home_url('/')); $cancel=add_query_arg(array('ebm_booking'=>$b->public_token,'payment'=>'cancelled'),home_url('/')); $data=self::request('checkout/sessions',array('mode'=>'payment','success_url'=>$success,'cancel_url'=>$cancel,'customer_email'=>$b->email,'client_reference_id'=>$booking_id,'payment_intent_data[metadata][booking_id]'=>$booking_id,'payment_intent_data[metadata][payment_type]'=>$type,'line_items[0][price_data][currency]'=>'gbp','line_items[0][price_data][product_data][name]'=>'Booking '.ucfirst($type),'line_items[0][price_data][unit_amount]'=>max(50,(int)round($amount*100)),'line_items[0][quantity]'=>1)); if(!is_wp_error($data)){$wpdb->insert(EBM_Helpers::table('transactions'),array('booking_id'=>$booking_id,'type'=>$type,'status'=>'checkout_created','amount'=>$amount,'provider'=>'stripe','provider_id'=>sanitize_text_field($data['id']??''),'created_at'=>current_time('mysql')),array('%d','%s','%s','%f','%s','%s','%s'));} return $data;}
	public static function webhook(WP_REST_Request $request){$event=json_decode($request->get_body(),true); if(empty($event['type'])){return new WP_REST_Response(array('ok'=>false),400);} if('checkout.session.completed'===$event['type']){global $wpdb;$session=$event['data']['object']??array();$booking_id=absint($session['client_reference_id']??0); if($booking_id){$wpdb->update(EBM_Helpers::table('bookings'),array('status'=>'confirmed','stripe_session_id'=>sanitize_text_field($session['id']??''),'updated_at'=>current_time('mysql')),array('id'=>$booking_id),array('%s','%s','%s'),array('%d')); EBM_Google::create_event($booking_id); EBM_Emails::confirmation($booking_id);}} return array('ok'=>true);}
}
